	for (int i = 0; i < rows; ++i) {
		for (int j = 0; j < cols; ++j) 
		{
			cin >> matrix[i][j];
		}
	}

	createSymmetricMatrix(matrix, rows, cols);

	cout << "Output:" << endl;
	printMatrix(matrix, rows, cols);

	return 0;
}

