int findpos(int arr[], int n, int k){
	for (int i = 0; i < n; i++){
		if (arr[i] == k) return i;
	}
}

void deleteAtPos(int arr[], int n, int k){
	int temp[100];
	for (int i = 0; i < k; i++){
		temp[i] = arr[i];
	}
	for (int i = k + 1; i < n; i++){
		temp[i - 1] = arr[i];
	}
	for (int i = 0; i < n - 1; i++){
		arr[i] = temp[i];
	}
	arr[n] = NULL;
}

void addAtStart(int arr[], int n, int k){
	int temp[100];
	temp[0] = k;
	for (int i = 0; i < n - 1; i++){
		temp[i + 1] = arr[i];
	}
	for (int i = 0; i < n; i++){
		arr[i] = temp[i];
	}
}

void Changing(int arr[], int changes[], int n, int k){
	for (int i = 0; i < k; i++){
		int pos = findpos(arr, n, changes[i]);
		deleteAtPos(arr, n, pos);
		addAtStart(arr, n, changes[i]);
	}
}

