	cout << "ID: " << pokemons[n].pokeID << endl;
	cout << "Pokemon name: " << pokemons[n].pokeName << endl;
	cout << "Type: " << pokemons[n].type1;
	if (pokemons[n].type2 != "NULL") cout << ", " << pokemons[n].type2;
	cout << endl << "Speed: " << pokemons[n].speed << endl;
