}

void fillArr (int a[], int n){
	for (int i=0; i<n; i++){
		a[i] = i+1;
	}
}

void deleteNum (int a[], int &n, int pos){
	for (int i=pos; i<n; i++){
		a[i] = a[i+1];
	}
	n--;
}

void change (int a[], int &n, int b[], int &b1){

	for (int i=0; i<b1; i++){
		for (int j=0; j<n; j++){
			if (b[i] == a[j]){
				deleteNum (a,n,j);
			}
		}
	}
	n = n + b1;

	for (int i=n-b1-1; i>=0; i--){
		a[i+b1] = a[i];
	}

	for (int i=0 ;i<b1; i++){
		a[i] = b[b1-1-i];
	}

