void sortMatrix(int a[][100], int m, int n){
    int mid = n / 2;
    for (int i = 0; i < m; i++){
        for (int j = 0; j < mid; j++){
            int temp = a[i][j];
            a[i][j] = a[i][n - j - 1];
            a[i][n - j - 1] = temp;
        }
    }
}
