}

void printArr (int arr [], int len) {
	for (int i = 0; i < len; i++) {
		if (i == len - 1) cout << arr [i];
		else cout << arr [i] << ' ';
	}
}

void setStack (int arr[], int n, int change_list[], int changes) {
	int pos = 0;
	while (pos < changes) {
		for (int j = 0; j < n; j ++) {
			if (arr[j] == change_list[pos]) {
				if (j == 0) continue;
				else {
					for (int k = j; k > 0; k--) {
						arr[k] = arr [k - 1];
					}
					arr [0] = change_list[pos];
				}
			}
		}
		pos ++;
	}
}

