void swap(int& a, int& b) {
    int temp = a;
    a = b;
    b = temp;
}

void createSymmetricMatrix(int** arr, int rows, int cols) {

    for (int i = 0; i < rows; i++) {

        for (int j = 0; j < cols / 2; j++) {
            swap(arr[i][j], arr[i][cols - 1 - j]);
        }
    }
}

