        for (int j = 0; j < cols; j++) {
            std::cin >> arr[i][j];
        }
    }


    createSymmetricMatrix(arr, rows, cols);


    std::cout << "Output:" << std::endl;
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
