const int Max = 100;

void exchange(int &a, int &b)
{
	int tempt = a;
	a = b;
	b = tempt;
}

void createMatrix(int a[][Max], int m, int n)
{
	int v1 = 0, v2 = n - 1;
	for (int i = 0; i < m; i++)
	{
		while (v1 < v2)
		{
			exchange(a[i][v1], a[i][v2]);
			v1 ++;
			v2 --;
		}
		v1 = 0; 
		v2 = n - 1;
	}
}

