		cin >> arr[i];
	}
}
void xuatmang(int arr[], int n)
{
	for (int i = 0; i < n; i++)
	{
		cout << arr[i] << " ";
	}
}
void doidia(int arr[],int a[],int n,int x)
{

    for(int i=x-1;i>=1;i--)
    {
        arr[i]=arr[i-1];
    }
    arr[0]=a[0];
}

